n  margin-top: 20px; \n  padding-top: 15px; \n  border-top: 1px solid #f1f5f9; \n}\n\n.btn-cancel-compact[_ngcontent-%COMP%] { \n  background: #f1f5f9; \n  color: #475569; \n  border: 1px solid #cbd5e1; \n  padding: 8px 16px; \n  font-size: 13px; \n  font-weight: 600; \n  border-radius: 6px; \n  cursor: pointer; \n}\n\n.btn-save-compact[_ngcontent-%COMP%] { \n  background: #0ea5e9; \n  color: white; \n  border: none; \n  padding: 8px 20px; \n  font-size: 13px; \n  font-weight: 600; \n  border-radius: 6px; \n  cursor: pointer; \n  display: inline-flex; \n  align-items: center; \n  gap: 6px; \n}\n\n.btn-save-compact.btn-dark-theme[_ngcontent-%COMP%] { \n  background: #0f172a !important; \n  color: #ffffff !important; \n}\n\n.btn-save-compact.btn-dark-theme[_ngcontent-%COMP%]:hover { \n  background: #1e293b !important; \n}\n\n.alert-box-compact[_ngcontent-%COMP%] { \n  padding: 10px; \n  border-radius: 6px; \n  margin-bottom: 14px; \n  font-size: 13px; \n  text-align: center; \n  font-weight: 600; \n}\n\n.alert-success[_ngcontent-%COMP%] { \n  background-color: #e6f4ea; \n  color: #137333; \n  border: 1px solid #ceead6; \n}\n\n.alert-danger[_ngcontent-%COMP%] { \n  background-color: #fef2f2; \n  color: #991b1b; \n  border: 1px solid #fee2e2; \n}\n\n\n.full-width-card-compact[_ngcontent-%COMP%] {\n  margin-top: 24px;\n  width: 100%;\n  box-sizing: border-box;\n}\n\n\n.horizontal-form-grid-compact[_ngcontent-%COMP%] {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 20px;\n  margin-top: 16px;\n  width: 100%;\n}\n\n\n.grid-span-full[_ngcontent-%COMP%] {\n  grid-column: span 3;\n}\n\n.input-with-icon-compact[_ngcontent-%COMP%] { \n  position: relative; \n  display: flex; \n  align-items: center; \n  width: 100%; \n}\n\n.input-with-icon-compact[_ngcontent-%COMP%]   i[_ngcontent-%COMP%] { \n  position: absolute; \n  left: 14px; \n  color: #64748b; \n  font-size: 14px; \n  z-index: 2;\n}\n\n.input-with-icon-compact[_ngcontent-%COMP%]   input[_ngcontent-%COM