import { Component, inject, OnInit, ChangeDetectorRef } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-profile-settings',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './profile-settings.component.html',
  styleUrl: './profile-settings.component.css'
})
export class ProfileSettingsComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  // 📝 Modèle de données enrichi pour le profil candidat
  profile = { 
    name: '', phone: '', email: '', address: '', avatar_logo: null,
    birth_date: '', linkedin: '', github: '', job_status: '', availability: '', job_type: '', location_pref: ''
  };
  
  backupProfile = { 
    name: '', phone: '', email: '', address: '', avatar_logo: null,
    birth_date: '', linkedin: '', github: '', job_status: '', availability: '', job_type: '', location_pref: ''
  };
  
  logoPreviewUrl: string | null = null;
  selectedFile: File | null = null;
  successMessage = '';
  
  // 🎛️ États de contrôle des formulaires indépendants
  isEditMode = false;         // Pour "Mon Profil Candidat"
  isProEditMode = false;      // 🆕 Pour "Profil Professionnel"
  isPasswordEditMode = false; // Pour "Sécurité du compte"

  passwordData = { currentPassword: '', newPassword: '', confirmPassword: '' };
  passwordSuccessMessage = '';
  passwordErrorMessage = '';

  ngOnInit() {
    this.loadCurrentProfile();
  }

  // 🔄 Bascule d'édition pour les informations personnelles
  toggleEditMode(mode: boolean) {
    this.isEditMode = mode;
    if (mode) {
      this.backupProfile = { ...this.profile };
    } else {
      this.profile = { ...this.backupProfile };
    }
    this.cdr.detectChanges();
  }

  // 🔄 Bascule d'édition pour le profil professionnel
  toggleProEditMode(mode: boolean) {
    this.isProEditMode = mode;
    if (mode) {
      this.backupProfile = { ...this.profile };
    } else {
      this.profile = { ...this.backupProfile };
    }
    this.cdr.detectChanges();
  }

  togglePasswordEditMode(mode: boolean) {
    this.isPasswordEditMode = mode;
    if (!mode) {
      this.passwordData = { currentPassword: '', newPassword: '', confirmPassword: '' };
    }
    this.cdr.detectChanges();
  }

  loadCurrentProfile() {
    const targetUrl = 'http://localhost:3000/api/candidate/profile/details'; 
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(async res => {
      if (res.ok) return res.json();
      throw new Error();
    })
    .then(data => {
      if (data) {
        this.profile.name = data.name || localStorage.getItem('name') || '';
        this.profile.phone = data.phone || '';
        this.profile.email = data.email || '';
        this.profile.address = data.address || '';
        
        // Formate correctement la date pour l'input HTML type="date"
        this.profile.birth_date = data.birth_date ? data.birth_date.split('T')[0] : '';
        this.profile.linkedin = data.linkedin || '';
        this.profile.github = data.github || '';
        this.profile.job_status = data.job_status || '';
        this.profile.availability = data.availability || '';
        this.profile.job_type = data.job_type || '';
        this.profile.location_pref = data.location_pref || '';
        
        if (data.avatar_logo) {
          const cleanFilename = data.avatar_logo.replace('/logos/', '').replace('uploads/logos/', '');
          this.logoPreviewUrl = `http://localhost:3000/logos/${cleanFilename}`;
        }
        this.cdr.detectChanges();
      }
    })
    .catch(() => {
      this.profile.name = localStorage.getItem('name') || '';
      this.cdr.detectChanges();
    });
  }

  onFileSelected(event: any) {
    const file = event.target.files[0];
    if (file) {
      this.selectedFile = file;
      
      const reader = new FileReader();
      reader.onload = () => {
        this.logoPreviewUrl = reader.result as string;
        this.cdr.detectChanges();
      };
      reader.readAsDataURL(file);

      const targetUrl = 'http://localhost:3000/api/candidate/profile/update-avatar';
      const token = localStorage.getItem('token');
      
      const formData = new FormData();
      formData.append('logo', file, file.name);

      fetch(targetUrl, {
        method: 'POST',
        headers: { 'Authorization': token ? `Bearer ${token}` : '' },
        body: formData
      })
      .then(async res => {
        if (!res.ok) {
          const errData = await res.json().catch(() => ({}));
          throw new Error(errData.message || "Échec d'envoi de la photo.");
        }
        return res.json();
      })
      .then(data => {
        this.successMessage = "Votre photo de profil a été mise à jour !";
        
        if (data && data.filename) {
          this.logoPreviewUrl = `http://localhost:3000/logos/${data.filename}`;
        }

        this.cdr.detectChanges();
        setTimeout(() => { this.successMessage = ''; this.cdr.detectChanges(); }, 3000);
      })
      .catch(err => {
        console.error("❌ Erreur Upload Frontend :", err);
        alert(err.message);
      });
    }
  }

  onSaveProfile(event: Event) {
    if (event) event.preventDefault();

    const targetUrl = 'http://localhost:3000/api/candidate/profile/update';
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'POST',
      headers: { 
        'Content-Type': 'application/json',
        'Authorization': token ? `Bearer ${token}` : '' 
      },
      body: JSON.stringify({
        name: this.profile.name,
        phone: this.profile.phone,
        address: this.profile.address,
        birth_date: this.profile.birth_date,
        linkedin: this.profile.linkedin,
        github: this.profile.github,
        job_status: this.profile.job_status,
        availability: this.profile.availability,
        job_type: this.profile.job_type,
        location_pref: this.profile.location_pref
      })
    })
    .then(async res => {
      if (!res.ok) throw new Error("Impossible de sauvegarder votre profil.");
      return res.json();
    })
    .then(resData => {
      this.successMessage = resData.message || "Les informations de votre profil ont été mises à jour.";
      this.isEditMode = false;
      this.isProEditMode = false; // Ferme l'état d'édition
      this.cdr.detectChanges();

      setTimeout(() => { this.successMessage = ''; this.cdr.detectChanges(); }, 3000);
    })
    .catch(err => alert(err.message));
  }

  onUpdatePassword(event: Event) {
    event.preventDefault();
    this.passwordSuccessMessage = '';
    this.passwordErrorMessage = '';

    if (this.passwordData.newPassword !== this.passwordData.confirmPassword) {
      this.passwordErrorMessage = "La confirmation ne correspond pas au nouveau mot de passe.";
      return;
    }

    if (this.passwordData.newPassword.length < 6) {
      this.passwordErrorMessage = "Le nouveau mot de passe doit contenir au moins 6 caractères.";
      return;
    }

    const targetUrl = 'http://localhost:3000/api/candidate/profile/change-password';
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': token ? `Bearer ${token}` : ''
      },
      body: JSON.stringify({
        currentPassword: this.passwordData.currentPassword,
        newPassword: this.passwordData.newPassword
      })
    })
    .then(async res => {
      const data = await res.json().catch(() => ({}));
      if (!res.ok) throw new Error(data.message || "Erreur lors du changement de mot de passe.");
      return data;
    })
    .then(data => {
      this.passwordSuccessMessage = data.message || "Votre mot de passe a été modifié avec succès !";
      this.passwordData = { currentPassword: '', newPassword: '', confirmPassword: '' };
      this.isPasswordEditMode = false;
      this.cdr.detectChanges();

      setTimeout(() => { this.passwordSuccessMessage = ''; this.cdr.detectChanges(); }, 4000);
    })
    .catch(err => {
      this.passwordErrorMessage = err.message;
      this.cdr.detectChanges();
    });
  }
}
<div class="profile-container-compact">

  <!-- HEADER -->
  <div class="card-header-flex-compact">
    <div class="card-header-left">
      <h3><i class="bi bi-person-fill-gear"></i> Mon Profil Candidat</h3>
    </div>
  </div>

  <!-- ALERTS -->
  @if (successMessage) {
    <div class="alert-box-compact alert-success">{{ successMessage }}</div>
  }

  @if (passwordSuccessMessage) {
    <div class="alert-box-compact alert-success">{{ passwordSuccessMessage }}</div>
  }

  @if (passwordErrorMessage) {
    <div class="alert-box-compact alert-danger">{{ passwordErrorMessage }}</div>
  }

  <!-- FORM GLOBAL -->
  <form (ngSubmit)="onSaveProfile($event)">

    <div class="profile-split-layout">

      <!-- ================= LEFT ================= -->
      <div class="profile-panel-card">

        <!-- AVATAR -->
        <div class="logo-section-compact">
          <div class="logo-preview-compact">

            @if (logoPreviewUrl) {
              <img [src]="logoPreviewUrl || 'assets/images/default-avatar.png'" class="avatar-img">
            } @else {
              <i class="bi bi-person-circle" style="font-size: 26px; color: #cbd5e1;"></i>
            }

          </div>

          <div class="upload-actions-compact">
            <input type="file" id="avatarInput" accept="image/*" (change)="onFileSelected($event)" style="display:none">

            <button type="button"
                    class="btn-secondary-upload-compact"
                    [disabled]="!isEditMode"
                    onclick="document.getElementById('avatarInput').click()">
              <i class="bi bi-camera-fill"></i> Modifier ma photo
            </button>
          </div>
        </div>

        <!-- FORM FIELDS -->
        <div class="compact-form-grid">

          <div class="form-group-compact">
            <label>Nom & Prénom *</label>
            @if (isEditMode) {
              <input [(ngModel)]="profile.name" name="name" required>
            } @else {
              <div class="static-text-compact">{{ profile.name || 'Non renseigné' }}</div>
            }
          </div>

          <div class="form-group-compact">
            <label>Téléphone *</label>
            @if (isEditMode) {
              <input [(ngModel)]="profile.phone" name="phone">
            } @else {
              <div class="static-text-compact">{{ profile.phone || 'Non renseigné' }}</div>
            }
          </div>

          <div class="form-group-compact">
            <label>Adresse *</label>
            @if (isEditMode) {
              <input [(ngModel)]="profile.address" name="address">
            } @else {
              <div class="static-text-compact">{{ profile.address || 'Non renseigné' }}</div>
            }
          </div>

        </div>

        <!-- ACTIONS -->
        <div class="form-actions-compact">

          @if (!isEditMode) {
            <button type="button" class="btn-save-compact" (click)="toggleEditMode(true)">
              <i class="bi bi-pencil-square"></i> Modifier
            </button>
          } @else {
            <button type="button" class="btn-cancel-compact" (click)="toggleEditMode(false)">
              Annuler
            </button>

            <button type="submit" class="btn-save-compact">
              <i class="bi bi-shield-check"></i> Enregistrer
            </button>
          }

        </div>

      </div>

      <!-- ================= RIGHT ================= -->
      <div class="profile-panel-card">

        <div class="panel-inner-title">
          <i class="bi bi-shield-lock-fill"></i> Sécurité du compte
        </div>

               <!-- Formulaire de Sécurité (Corrigé avec le Nouveau Mot de Passe) -->
        <div class="compact-form-grid">

          <!-- 1. Mot de passe actuel -->
          <div class="form-group-compact">
            <label>Mot de passe actuel *</label>
            @if (isPasswordEditMode) {
              <input type="password" [(ngModel)]="passwordData.currentPassword" name="currentPassword" required placeholder="••••••••">
            } @else {
              <div class="static-text-compact">••••••••</div>
            }
          </div>

          <!-- 2. 🟢 CHAMP RÉINTRODUIT : Nouveau mot de passe -->
          <div class="form-group-compact">
            <label>Nouveau mot de passe *</label>
            @if (isPasswordEditMode) {
              <input type="password" [(ngModel)]="passwordData.newPassword" name="newPassword" required placeholder="Min. 6 caractères">
            } @else {
              <div class="static-text-compact">••••••••</div>
            }
          </div>

          <!-- 3. Confirmation -->
          <div class="form-group-compact">
            <label>Confirmation *</label>
            @if (isPasswordEditMode) {
              <input type="password" [(ngModel)]="passwordData.confirmPassword" name="confirmPassword" required placeholder="••••••••">
            } @else {
              <div class="static-text-compact">••••••••</div>
            }
          </div>

        </div>


        <div class="form-actions-compact">

          @if (!isPasswordEditMode) {
            <button type="button" class="btn-save-compact btn-dark-theme"
                    (click)="togglePasswordEditMode(true)">
              <i class="bi bi-key-fill"></i> Modifier mot de passe
            </button>
          } @else {

            <button type="button" class="btn-cancel-compact"
                    (click)="togglePasswordEditMode(false)">
              Annuler
            </button>

            <button type="button" class="btn-save-compact btn-dark-theme"
                    (click)="onUpdatePassword($event)">
              Enregistrer
            </button>

          }

        </div>

      </div>

    </div>

    <!-- ================= FULL WIDTH ================= -->
    <div class="profile-panel-card full-width-card-compact">

      <!-- 🟢 EN-TÊTE ALIGNÉ AVEC BOUTON D'ACTION ISOLÉ -->
      <div class="card-header-flex-compact" style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px;">
        <div class="panel-inner-title" style="margin-bottom: 0;">
          <i class="bi bi-briefcase-fill"></i> Profil professionnel
        </div>
        <div>
          @if (!isProEditMode) {
            <button type="button" class="btn-save-compact" (click)="toggleProEditMode(true)">
              <i class="bi bi-pencil-square"></i> Modifier
            </button>
          } @else {
            <button type="button" class="btn-cancel-compact" style="padding: 5px 10px; font-size: 12px; margin-right: 5px;" (click)="toggleProEditMode(false)">
              Annuler
            </button>
            <button type="submit" class="btn-save-compact" style="padding: 5px 12px; font-size: 12px;">
              <i class="bi bi-shield-check"></i> Enregistrer
            </button>
          }
        </div>
      </div>

      <div class="horizontal-form-grid-compact">

        <div class="form-group-compact">
          <label>Date de naissance</label>

          @if (!isProEditMode) {
            <div class="static-text-compact">
              {{ profile.birth_date ? (profile.birth_date | date:'dd/MM/yyyy') : 'Non renseignée' }}
            </div>
          } @else {
            <input type="date" [(ngModel)]="profile.birth_date" name="birth_date">
          }
        </div>

        <div class="form-group-compact">
          <label>LinkedIn</label>

          @if (!isProEditMode) {
            <div class="static-text-compact">
              {{ profile.linkedin || 'Non renseigné' }}
            </div>
          } @else {
            <input type="url" [(ngModel)]="profile.linkedin" name="linkedin">
          }
        </div>

        <div class="form-group-compact">
          <label>GitHub</label>

          @if (!isProEditMode) {
            <div class="static-text-compact">
              {{ profile.github || 'Non renseigné' }}
            </div>
          } @else {
            <input type="url" [(ngModel)]="profile.github" name="github">
          }
        </div>

        <div class="form-group-compact">
          <label>Situation</label>

          @if (!isProEditMode) {
            <div class="static-text-compact">{{ profile.job_status || 'Non renseignée' }}</div>
          } @else {
            <select [(ngModel)]="profile.job_status" name="job_status">
              <option value="">Choisir</option>
              <option value="En recherche active">En recherche active</option>
              <option value="En poste">En poste</option>
              <option value="Étudiant">Étudiant</option>
              <option value="Freelance">Freelance</option>
            </select>
          }
        </div>

        <!-- DISPONIBILITÉ -->
        <div class="form-group-compact">
          <label>Disponibilité</label>

          @if (!isProEditMode) {
            <div class="static-text-compact">{{ profile.availability || 'Non renseignée' }}</div>
          } @else {
            <select [(ngModel)]="profile.availability" name="availability">
              <option value="">Choisir</option>
              <option value="Immédiate">Immédiate</option>
              <option value="1 mois">1 mois</option>
              <option value="3 mois">3 mois</option>
            </select>
          }
        </div>

        <!-- CONTRAT -->
        <div class="form-group-compact">
          <label>Contrat recherché</label>

          @if (!isProEditMode) {
            <div class="static-text-compact">{{ profile.job_type || 'Non renseigné' }}</div>
          } @else {
            <select [(ngModel)]="profile.job_type" name="job_type">
              <option value="">Choisir</option>
              <option value="CDI">CDI</option>
              <option value="CDD">CDD</option>
              <option value="Freelance">Freelance</option>
              <option value="Stage">Stage</option>
            </select>
          }
        </div>

      </div>

    </div>

  </form>
</div>
